#include <stdio.h>

int main() {
    int T, N;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        int a[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                scanf("%d", &a[i][j]);
            }
        }
        int max_points = 0;
        for (int i = 0; i < N; i++) {
            int points = 0;
            for (int j = 0; j < N; j++) {
                if (a[i][j] == 1) points += 3;
            }
            max_points = (points > max_points) ? points : max_points;
        }
        for (int i = 0; i < N; i++) {
            int points = 0;
            int unplayed = 0;
            for (int j = 0; j < N; j++) {
                if (a[i][j] == 1) points += 3;
                else if (a[i][j] == 2) unplayed++;
            }
            if (points + unplayed * 3 < max_points) printf("0");
            else printf("1");
        }
        printf("\n");
    }
    return 0;
}

