import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[][] a = new int[N][N];
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < N; j++) {
                    a[i][j] = sc.nextInt();
                }
            }
            int max_points = 0;
            for (int i = 0; i < N; i++) {
                int points = 0;
                for (int j = 0; j < N; j++) {
                    if (a[i][j] == 1) points += 3;
                }
                max_points = Math.max(points, max_points);
            }
            for (int i = 0; i < N; i++) {
                int points = 0;
                int unplayed = 0;
                for (int j = 0; j < N; j++) {
                    if (a[i][j] == 1) points += 3;
                    else if (a[i][j] == 2) unplayed++;
                }
                if (points + unplayed * 3 < max_points) System.out.print("0");
                else System.out.print("1");
            }
            System.out.println();
        }
    }
}

